import{_ as a,o as i,c as e,ag as t}from"./chunks/framework.BLeoozAw.js";const n="/Awesome-SRC-experience/img/1_gJy6VL-cev_f7AJYhexNUA.jpg",p="/Awesome-SRC-experience/img/1_k8jW7uXrw6p-_-iphOWFYw.jpg",l="/Awesome-SRC-experience/img/1_DOtsrYi_CHbtQMs_KB4KpQ.jpg",h="/Awesome-SRC-experience/img/1_s1JhYLJSoteMFI30xYkZ_Q.jpg",r="/Awesome-SRC-experience/img/2.jpg",C=JSON.parse('{"title":"子域名模糊测试：admin-panels前端验证绕过拿下SQL，升级RCE","description":"Awesome SRC Experience - 子域名模糊测试：admin-panels前端验证绕过拿下SQL，升级RCE","frontmatter":{"title":"子域名模糊测试：admin-panels前端验证绕过拿下SQL，升级RCE","description":"Awesome SRC Experience - 子域名模糊测试：admin-panels前端验证绕过拿下SQL，升级RCE","target_type":"web","author":"Awesome-SRC Contributor","difficulty":"Medium"},"headers":[],"relativePath":"experience/web/admin-panels/unauth-admin.md","filePath":"experience/web/admin-panels/unauth-admin.md"}'),o={name:"experience/web/admin-panels/unauth-admin.md"};function d(c,s,k,g,m,F){return i(),e("div",null,[...s[0]||(s[0]=[t('<h1 id="子域名模糊测试-admin-panels前端验证绕过拿下sql-升级rce" tabindex="-1">子域名模糊测试：admin-panels前端验证绕过拿下SQL，升级RCE <a class="header-anchor" href="#子域名模糊测试-admin-panels前端验证绕过拿下sql-升级rce" aria-label="Permalink to &quot;子域名模糊测试：admin-panels前端验证绕过拿下SQL，升级RCE&quot;">​</a></h1><p>该文章的作者是<strong>Abdullah Nawaf</strong>，全职漏洞赏金猎人，在BugCrowd中排名前50，P1漏洞排名第11。</p><p>本文介绍了<strong>如何使用子域名模糊测试和链接多个漏洞来获取完整的RCE（远程代码执行）漏洞。</strong></p><h2 id="描述" tabindex="-1">描述 <a class="header-anchor" href="#描述" aria-label="Permalink to &quot;描述&quot;">​</a></h2><p>2022年的时候，作者在Bugcrowd上报告了一个私人程序带的Auth Bypass导致SQLI&amp;RCE，该漏洞在报告后一天就被修复。</p><p>2024年3月，作者决定重新测试他们的旧bug。他们的测试目标为：<code>admin.Target.com</code> 通过使用下面的命令进行子域模糊测试：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffuf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -w</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /subdomain_megalist.txt</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;https://adminFUZZ.Target.com&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -t</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 350</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -mc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> all</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -fs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span></code></pre></div><blockquote><p>模糊测试字典：<code>subdomain_megalist.txt</code> 放在最后附录部分。</p></blockquote><p>使用上述命令，作者发现了子域名：<code>admintest.Target.com</code></p><p><img src="'+n+'" alt=""></p><blockquote><p>在图片中可以看到很多错误信息，但这没关系，因为在进行子域模糊测试时，错误信息表示这些子域名不可用。</p></blockquote><p><code>admintest.Target.com</code>很可能存在漏洞，因为它与原始子域<code>admin.Target.com</code>拥有相同的后端。 下面将逐个讨论作者发现的漏洞。</p><h2 id="认证绕过-auth-bypass-和浏览器自动完成-bac" tabindex="-1">认证绕过（Auth Bypass）和浏览器自动完成（BAC） <a class="header-anchor" href="#认证绕过-auth-bypass-和浏览器自动完成-bac" aria-label="Permalink to &quot;认证绕过（Auth Bypass）和浏览器自动完成（BAC）&quot;">​</a></h2><p><code>https://admintest.Target.com</code>被重定向到<code>https://admintest.Target.come/admin/login.aspx</code></p><p>在阅读js文件时，我们发现了一个文件&#39;<a href="https://admintest.Target.com/admin/main.aspx" target="_blank" rel="noreferrer">https://admintest.Target.com/admin/main.aspx</a>&#39;。 直接在浏览器会再次重定向到登录页面，但在Burp中我们发现了一些有趣的东西。</p><p><img src="'+p+'" alt=""></p><p>重定向响应的<code>Content-Length</code> 大小异常的大（怀疑前端验证造成）。通过删除三个访问头，最终获得完全访问权限，至此打开访问面板。</p><p><img src="'+l+`" alt=""></p><p>使用Burp拦截响应，并修改以下访问头。</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">将 302 Moved Temporarily 改为 200 OK</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">删除 Location: /admin/Login.aspx?logout=y</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">删除 html redirect code</span></span></code></pre></div><p>至此，作者成功实现了身份验证绕过，获得平台全部功能。随后通过深度挖掘，发现名为<code>adduser.aspx</code>的文件，该文件使用与<code>main.aspx</code>相同的技巧将访问重定向到登录页面。</p><p>利用上述相同的绕过方法，成功访问<code>adduser.aspx</code>页面并创建了一个管理员账户。 此外，还发现了一个无需身份验证即可显示<strong>管理员密码和用户名</strong>的地方。</p><p><img src="`+h+`" alt=""></p><h2 id="sql注入攻击" tabindex="-1">SQL注入攻击 <a class="header-anchor" href="#sql注入攻击" aria-label="Permalink to &quot;SQL注入攻击&quot;">​</a></h2><p>添加管理员账户后，就可以直接登录系统，这比使用认证绕过更方便。 随后，作者发现一个名为<code>SQLQuery.aspx</code>的端点，从名称就可以猜出它的功能。 首先，我尝试了以下的查询：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Select</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> users;</span></span></code></pre></div><p>结果，直接能看到所有用户的信息，包括密码、电子邮件和用户名。</p><h2 id="远程代码执行-rce-漏洞" tabindex="-1">远程代码执行（RCE）漏洞 <a class="header-anchor" href="#远程代码执行-rce-漏洞" aria-label="Permalink to &quot;远程代码执行（RCE）漏洞&quot;">​</a></h2><p>由于数据库是<code>mssql</code>，作者尝试使用<code>xp_cmdshell</code>将其升级为RCE。</p><blockquote><p><code>xp_cmdshell</code> 存储过程是 SQL Server 中的一个强大功能，可用于在 SQL 语句中执行系统命令。它允许数据库管理员或具有适当权限的用户直接从 SQL Server 访问操作系统功能。默认禁用，攻击者可以利用它来窃取敏感数据、安装恶意软件甚至完全控制系统。</p></blockquote><p>简单来说，<code>xp_cmdshell</code> 允许用户通过<code>mssql</code>执行系统命令。 默认情况下，它是禁用的，但是可以轻松启用它。例如使用<code>sqlmap</code>工具的<code>--os-shell</code>参数。 不过这里能够直接向数据库发送查询，就无需使用<code>sqlmap</code>。 要让<code>xp_cmdshell</code>正常工作，我们首先需要使用以下查询启用它：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SP_CONFIGURE </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;show advanced options&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RECONFIGURE</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SP_CONFIGURE </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;xp_cmdshell&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RECONFIGURE</span></span></code></pre></div><p>然后，执行<code>xp_cmdshell &#39;whoami&#39;</code> 拿下RCE漏洞。</p><p><img src="`+r+`" alt=""></p><p>作者将发现的多个问题整理成一份报告，并将另一个端点中发现的另一个SQL注入漏洞单独报告，最终获得了35000美元的赏金。</p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><ol><li><strong>始终检查Burp中的重定向响应。</strong></li></ol><p>作者发现了许多类似的身份验证绕过漏洞，作者第一次获得赏金是在2020年，利用的是相同的技巧：<code>/admin/admin.php</code>重定向到<code>login.php</code>。但是，当使用Burp查看响应时，发现<code>admin.php</code>页面可以正常工作，只是前端重定向。</p><ol start="2"><li><strong>如果你在子域名中发现并修复了漏洞请尝试使用子域名模糊测试。</strong></li></ol><p><strong>子域名模糊测试参考格式：</strong></p><div class="language-context vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">context</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>admin-FUZZ.target.com E.G: admin-stg.target.com</span></span>
<span class="line"><span>FUZZ-admin.target.com E.G: cert-admin.target.com</span></span>
<span class="line"><span>adminFUZZ.target.com  E.G: admintest.target.com</span></span>
<span class="line"><span>FUZZadmin.target.com  E.G  testadmin.target.com</span></span>
<span class="line"><span>admin.FUZZ.target.com E.G: admin.dev.target.com</span></span></code></pre></div><p><strong>模糊测试命令：</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffuf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -w</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /subdomain_megalist.txt</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;https://adminFUZZ.Target.com&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -t</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 350</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -mc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> all</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -fs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 线程数</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 根据你的t带宽设置，尽量不要设置太高，否则你可能会错过很多正常的子域名</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ,</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">,作者使用vps将线程设置为</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 350</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 。</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-mc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> all</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 代表匹配所有的响应码</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 比如</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 200,302,403</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 这一点非常重要。</span></span></code></pre></div><ol start="3"><li><p><strong>在提交报告之前尝试升级漏洞。</strong></p></li><li><p><strong>质量大于数量</strong></p></li></ol><blockquote><p>当你发现多个漏洞或将多个漏洞组合在一起时，请尝试将其作为一份报告提交，你将获得更高的赏金！</p></blockquote><h2 id="附录" tabindex="-1">附录： <a class="header-anchor" href="#附录" aria-label="Permalink to &quot;附录：&quot;">​</a></h2><h3 id="子域名爆破字典" tabindex="-1">子域名爆破字典： <a class="header-anchor" href="#子域名爆破字典" aria-label="Permalink to &quot;子域名爆破字典：&quot;">​</a></h3><p><a href="https://github.com/netsecurity-as/subfuz/blob/master/subdomain_megalist.txt" target="_blank" rel="noreferrer">subdomain_megalist.txt</a></p><p>更多更大的字典：</p><p><a href="https://github.com/danielmiessler/SecLists/tree/master/Discovery/DNS" target="_blank" rel="noreferrer">SecLists/Discovery/DNS </a></p><h2 id="使用的工具" tabindex="-1">使用的工具： <a class="header-anchor" href="#使用的工具" aria-label="Permalink to &quot;使用的工具：&quot;">​</a></h2><p>模糊测试神器：<a href="https://github.com/ffuf/ffuf" target="_blank" rel="noreferrer">ffuf</a></p><p>Web安全测试神器：<a href="https://portswigger.net/burp" target="_blank" rel="noreferrer">Burp suite</a></p><p>SQL注入检测和利用神器：<a href="https://github.com/sqlmapproject/sqlmap" target="_blank" rel="noreferrer">sqlmap</a></p>`,54)])])}const b=a(o,[["render",d]]);export{C as __pageData,b as default};
